/**
 * Result of checking if a peer should be reconnected
 */

public enum ReconnectionStatus: Equatable, Hashable {
    
    /**
     * Ready to attempt reconnection
     */
    case ready
    /**
     * Waiting for backoff delay to expire
     */
    case waiting(
        /**
         * Time remaining until next attempt is allowed in milliseconds
         */remainingMs: UInt64
    )
    /**
     * Maximum attempts exceeded, peer is abandoned
     */
    case exhausted(
        /**
         * Number of attempts that were made
         */attempts: UInt32
    )
    /**
     * Peer is not being tracked for reconnection
     */
    case notTracked





}

#if compiler(>=6)
extension ReconnectionStatus: Sendable {}
#endif

#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeReconnectionStatus: FfiConverterRustBuffer {
    typealias SwiftType = ReconnectionStatus

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> ReconnectionStatus {
        let variant: Int32 = try readInt(&buf)
        switch variant {
        
        case 1: return .ready
        
        case 2: return .waiting(remainingMs: try FfiConverterUInt64.read(from: &buf)
        )
        
        case 3: return .exhausted(attempts: try FfiConverterUInt32.read(from: &buf)
        )
        
        case 4: return .notTracked
        
        default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: ReconnectionStatus, into buf: inout [UInt8]) {
        switch value {
        
        
        case .ready:
            writeInt(&buf, Int32(1))
        
        
        case let .waiting(remainingMs):
            writeInt(&buf, Int32(2))
            FfiConverterUInt64.write(remainingMs, into: &buf)
            
        
        case let .exhausted(attempts):
            writeInt(&buf, Int32(3))
            FfiConverterUInt32.write(attempts, into: &buf)
            
        
        case .notTracked:
            writeInt(&buf, Int32(4))
        
        }
    }
}


