/**
 * UniFFI-exported callback that receives JSON-serialized
 * [`peat_mesh::sync::Document`]s decoded from inbound BLE translator
 * frames (ADR-059 Amendment 2; back-edge-free shape preserved by Slice 4.b).
 *
 * Same wiring point on `PeatMesh` (set via
 * [`PeatMesh::set_decoded_document_json_callback`](crate::peat_mesh::PeatMesh::set_decoded_document_json_callback)),
 * same firing path inside the receive dispatch — fires on every
 * successfully-decoded 0xB6 frame.
 *
 * **Why JSON-string instead of typed `Document`.** UniFFI 0.31 can't
 * pass `peat_mesh::sync::Document` across the FFI boundary without
 * bindings for the entire schema graph (`Document`, `Field`,
 * `DocumentId`, all of `serde_json::Value`'s shape). Hosts that
 * already round-trip docs as JSON strings via peat-ffi's
 * `publishDocumentWithOrigin`-shaped FFI gain a directly-forwardable
 * payload, and peat-btle has no peat-mesh dep at all (Slice 4.b
 * closed that back-edge), so the JSON shape is the only one this
 * crate produces.
 *
 * `PeatEvent::TranslatorNoCallback` fires when no callback is
 * installed (the release-skew window before any host has wired
 * anything up).
 */
public protocol DecodedDocumentJsonCallback: AnyObject, Sendable {
    
    /**
     * `collection` is the BleTranslator collection name. `doc_json`
     * is the serde-JSON serialization of the decoded document.
     * `peer` is the BLE peer identifier from the receive context.
     */
    func onDocument(collection: String, docJson: String, peer: String?) 
    
}


// Put the implementation in a struct so we don't pollute the top-level namespace
fileprivate struct UniffiCallbackInterfaceDecodedDocumentJsonCallback {

    // Create the VTable using a series of closures.
    // Swift automatically converts these into C callback functions.
    //
    // This creates 1-element array, since this seems to be the only way to construct a const
    // pointer that we can pass to the Rust code.
    static let vtable: [UniffiVTableCallbackInterfaceDecodedDocumentJsonCallback] = [UniffiVTableCallbackInterfaceDecodedDocumentJsonCallback(
        uniffiFree: { (uniffiHandle: UInt64) -> () in
            do {
                try FfiConverterCallbackInterfaceDecodedDocumentJsonCallback.handleMap.remove(handle: uniffiHandle)
            } catch {
                print("Uniffi callback interface DecodedDocumentJsonCallback: handle missing in uniffiFree")
            }
        },
        uniffiClone: { (uniffiHandle: UInt64) -> UInt64 in
            do {
                return try FfiConverterCallbackInterfaceDecodedDocumentJsonCallback.handleMap.clone(handle: uniffiHandle)
            } catch {
                fatalError("Uniffi callback interface DecodedDocumentJsonCallback: handle missing in uniffiClone")
            }
        },
        onDocument: { (
            uniffiHandle: UInt64,
            collection: RustBuffer,
            docJson: RustBuffer,
            peer: RustBuffer,
            uniffiOutReturn: UnsafeMutableRawPointer,
            uniffiCallStatus: UnsafeMutablePointer<RustCallStatus>
        ) in
            let makeCall = {
                () throws -> () in
                guard let uniffiObj = try? FfiConverterCallbackInterfaceDecodedDocumentJsonCallback.handleMap.get(handle: uniffiHandle) else {
                    throw UniffiInternalError.unexpectedStaleHandle
                }
                return uniffiObj.onDocument(
                     collection: try FfiConverterString.lift(collection),
                     docJson: try FfiConverterString.lift(docJson),
                     peer: try FfiConverterOptionString.lift(peer)
                )
            }

            
            let writeReturn = { () }
            uniffiTraitInterfaceCall(
                callStatus: uniffiCallStatus,
                makeCall: makeCall,
                writeReturn: writeReturn
            )
        }
    )]
}

private func uniffiCallbackInitDecodedDocumentJsonCallback() {
    uniffi_peat_btle_fn_init_callback_vtable_decodeddocumentjsoncallback(UniffiCallbackInterfaceDecodedDocumentJsonCallback.vtable)
}

