/**
 * Create a PeatMesh with encryption enabled (returns null if secret is wrong length)
 */
public func createPeatMeshWithEncryption(nodeId: UInt32, callsign: String, meshId: String, encryptionSecret: Data) -> PeatMesh?  {
    return try!  FfiConverterOptionTypePeatMesh.lift(try! rustCall() {
    uniffi_peat_btle_fn_func_create_peat_mesh_with_encryption(
        FfiConverterUInt32.lower(nodeId),
        FfiConverterString.lower(callsign),
        FfiConverterString.lower(meshId),
        FfiConverterData.lower(encryptionSecret),$0
    )
})
}
